/**
 * BarChart.jsx
 * ─────────────────────────────────────────────────────────────
 * Gráfica de barras que compara ingresos vs gastos por mes.
 * Genera los últimos 6 meses agrupando las transacciones.
 *
 * Props:
 *   transactions — array de transacciones del usuario
 */

import { useEffect, useRef, useMemo } from 'react'
import {
  Chart, BarElement, CategoryScale, LinearScale,
  Tooltip, Legend, BarController,
} from 'chart.js'
import { formatCurrency } from '../../utils/formatCurrency'

Chart.register(BarElement, CategoryScale, LinearScale, Tooltip, Legend, BarController)

/** Agrupa transacciones por mes (últimos N meses) */
const groupByMonth = (transactions, months = 6) => {
  const now    = new Date()
  const result = {}

  // Inicializar los últimos N meses con ceros
  for (let i = months - 1; i >= 0; i--) {
    const d   = new Date(now.getFullYear(), now.getMonth() - i, 1)
    const key = d.toLocaleDateString('es-CO', { month: 'short', year: '2-digit' })
    result[key] = { income: 0, expense: 0 }
  }

  // Acumular transacciones en su mes correspondiente
  transactions.forEach((t) => {
    const d   = new Date(t.date)
    const key = d.toLocaleDateString('es-CO', { month: 'short', year: '2-digit' })
    if (result[key]) {
      result[key][t.type] += t.amount
    }
  })

  return result
}

export default function BarChart({ transactions = [] }) {
  const canvasRef = useRef(null)
  const chartRef  = useRef(null)

  const grouped = useMemo(() => groupByMonth(transactions), [transactions])

  useEffect(() => {
    if (!canvasRef.current) return
    if (chartRef.current) chartRef.current.destroy()

    const labels  = Object.keys(grouped)
    const incomes  = labels.map((l) => grouped[l].income)
    const expenses = labels.map((l) => grouped[l].expense)

    const textColor   = getComputedStyle(document.documentElement).getPropertyValue('--text-secondary').trim()
    const borderColor = getComputedStyle(document.documentElement).getPropertyValue('--border-default').trim()
    const cardBg      = getComputedStyle(document.documentElement).getPropertyValue('--surface-card').trim()

    chartRef.current = new Chart(canvasRef.current, {
      type: 'bar',
      data: {
        labels,
        datasets: [
          {
            label:           'Ingresos',
            data:            incomes,
            backgroundColor: 'rgba(22, 163, 74, 0.75)',
            borderRadius:    4,
            borderSkipped:   false,
          },
          {
            label:           'Gastos',
            data:            expenses,
            backgroundColor: 'rgba(220, 38, 38, 0.65)',
            borderRadius:    4,
            borderSkipped:   false,
          },
        ],
      },
      options: {
        responsive:          true,
        maintainAspectRatio: true,
        interaction: { mode: 'index', intersect: false },
        plugins: {
          legend: {
            position: 'top',
            align:    'end',
            labels: {
              padding:         16,
              usePointStyle:   true,
              pointStyleWidth: 8,
              font:            { size: 12, family: 'DM Sans' },
              color:           textColor,
            },
          },
          tooltip: {
            callbacks: { label: (ctx) => ` ${ctx.dataset.label}: ${formatCurrency(ctx.raw)}` },
            backgroundColor: cardBg,
            titleColor:      getComputedStyle(document.documentElement).getPropertyValue('--text-primary').trim(),
            bodyColor:       textColor,
            borderColor,
            borderWidth:     1,
            padding:         12,
          },
        },
        scales: {
          x: {
            grid:  { display: false },
            ticks: { color: textColor, font: { size: 11, family: 'DM Sans' } },
            border: { color: borderColor },
          },
          y: {
            grid:  { color: borderColor },
            ticks: {
              color:    textColor,
              font:     { size: 11, family: 'DM Sans' },
              callback: (v) => `$${(v / 1000).toFixed(0)}k`,
            },
            border: { dash: [4, 4], color: 'transparent' },
          },
        },
      },
    })

    return () => { if (chartRef.current) chartRef.current.destroy() }
  }, [grouped])

  return <canvas ref={canvasRef} />
}
